window.MATCHS_CSV_B64 = "";

﻿var DASHBOARD_STATE = {
    allMatches: [],
    filteredMatches: [],
    charts: {
        monthly: null,
        competition: null,
        weekday: null,
        hostClubs: null
    }
};

var CHART_WARNING_SHOWN = false;

document.addEventListener("DOMContentLoaded", function () {
    initDashboard();
});

async function initDashboard() {
    var seasonFilter = document.getElementById("season-filter");
    var competitionFilter = document.getElementById("competition-filter");

    if (seasonFilter) {
        seasonFilter.addEventListener("change", applyFilters);
    }

    if (competitionFilter) {
        competitionFilter.addEventListener("change", applyFilters);
    }

    await loadCsvData();
}

async function loadCsvData() {
    try {
        setStatus("Chargement du fichier CSV...");

        var embeddedCsvText = resolveEmbeddedCsvText();

        if (!looksLikeMatchCsv(embeddedCsvText)) {
            throw new Error("source embarquée non chargée ou invalide.");
        }

        processCsvText(embeddedCsvText, "source locale embarquée");
    } catch (error) {
        setStatus("Erreur de chargement automatique: " + error.message, true);
        var range = document.getElementById("data-range");
        if (range) {
            range.textContent = "Chargement automatique indisponible. Vérifie le chargement de matchs_embedded.js puis actualise.";
        }
    }
}

function resolveEmbeddedCsvText() {
    if (typeof window === "undefined") return "";

    if (typeof window.MATCHS_CSV_TEXT === "string" && window.MATCHS_CSV_TEXT.length > 0) {
        return window.MATCHS_CSV_TEXT;
    }

    if (typeof window.MATCHS_CSV_B64 === "string" && window.MATCHS_CSV_B64.length > 0) {
        return decodeBase64Utf8(window.MATCHS_CSV_B64);
    }

    return "";
}

function decodeBase64Utf8(base64) {
    try {
        var binary = atob(base64);
        var bytes = new Uint8Array(binary.length);

        for (var i = 0; i < binary.length; i++) {
            bytes[i] = binary.charCodeAt(i);
        }

        if (typeof TextDecoder !== "undefined") {
            return new TextDecoder("utf-8").decode(bytes);
        }

        var escaped = "";
        for (var j = 0; j < bytes.length; j++) {
            escaped += "%" + bytes[j].toString(16).padStart(2, "0");
        }
        return decodeURIComponent(escaped);
    } catch (_) {
        return "";
    }
}

function looksLikeMatchCsv(text) {
    if (!text) return false;
    return text.indexOf("arbitre_1_nom") !== -1 && text.indexOf("competition") !== -1;
}

function processCsvText(csvText, sourceLabel) {
    var rows = parseCsvRows(csvText);
    DASHBOARD_STATE.allMatches = buildElliotDataset(rows);

    if (DASHBOARD_STATE.allMatches.length === 0) {
        throw new Error("Aucun match trouvé pour Elliot FEROUX dans les données.");
    }

    resetFilterOptions();
    populateFilters(DASHBOARD_STATE.allMatches);
    updateDataRange(DASHBOARD_STATE.allMatches);
    applyFilters();

    setStatus(DASHBOARD_STATE.allMatches.length + " convocations Elliot chargées (" + sourceLabel + ").");
}

function parseCsvRows(csvText) {
    if (typeof Papa !== "undefined") {
        var parsed = Papa.parse(csvText, {
            header: true,
            skipEmptyLines: true
        });

        return parsed.data || [];
    }

    return parseCsvRowsManual(csvText);
}

function parseCsvRowsManual(csvText) {
    var rows = [];
    var currentRow = [];
    var currentField = "";
    var inQuotes = false;

    for (var i = 0; i < csvText.length; i++) {
        var char = csvText[i];
        var nextChar = csvText[i + 1];

        if (inQuotes) {
            if (char === "\"") {
                if (nextChar === "\"") {
                    currentField += "\"";
                    i++;
                } else {
                    inQuotes = false;
                }
            } else {
                currentField += char;
            }
            continue;
        }

        if (char === "\"") {
            inQuotes = true;
        } else if (char === ",") {
            currentRow.push(currentField);
            currentField = "";
        } else if (char === "\n") {
            currentRow.push(currentField);
            rows.push(currentRow);
            currentRow = [];
            currentField = "";
        } else if (char !== "\r") {
            currentField += char;
        }
    }

    if (currentField.length > 0 || currentRow.length > 0) {
        currentRow.push(currentField);
        rows.push(currentRow);
    }

    if (rows.length === 0) return [];

    var headers = rows[0].map(function (header) {
        return String(header || "").replace(/^\uFEFF/, "").trim();
    });

    var objects = [];

    for (var rowIndex = 1; rowIndex < rows.length; rowIndex++) {
        var row = rows[rowIndex];
        if (!row || row.length === 0) continue;

        var obj = {};
        var nonEmpty = false;

        for (var col = 0; col < headers.length; col++) {
            var key = headers[col];
            var value = row[col] !== undefined ? row[col] : "";
            if (String(value).trim() !== "") nonEmpty = true;
            obj[key] = value;
        }

        if (nonEmpty) {
            objects.push(obj);
        }
    }

    return objects;
}

function resetFilterOptions() {
    var seasonFilter = document.getElementById("season-filter");
    var competitionFilter = document.getElementById("competition-filter");

    if (seasonFilter) {
        seasonFilter.innerHTML = "<option value=\"all\">Toutes les saisons</option>";
    }

    if (competitionFilter) {
        competitionFilter.innerHTML = "<option value=\"all\">Toutes les compétitions</option>";
    }
}

function buildElliotDataset(rows) {
    var matches = [];

    rows.forEach(function (row) {
        for (var i = 1; i <= 4; i++) {
            var name = row["arbitre_" + i + "_nom"];
            if (!isElliotName(name)) continue;

            var dateObj = parseFrenchDate(row.date);
            var indemnity = parseNumber(row["arbitre_" + i + "_indemnite_eur"]);

            matches.push({
                dateRaw: row.date || "",
                dateObj: dateObj,
                heure: (row.heure || "").trim(),
                timeMinutes: parseTimeToMinutes(row.heure),
                competition: cleanText(row.competition) || "Non renseignée",
                visiteur: cleanText(row.groupe_sportif_visiteur) || "-",
                recevant: cleanText(row.groupe_sportif_recevant) || "-",
                salle: cleanText(row.adresse_salle) || "-",
                role: i,
                season: computeSeason(dateObj),
                indemnity: indemnity,
                indemnityKnown: indemnity !== null
            });
            break;
        }
    });

    matches.sort(function (a, b) {
        var aTime = a.dateObj ? a.dateObj.getTime() : -Infinity;
        var bTime = b.dateObj ? b.dateObj.getTime() : -Infinity;
        if (aTime !== bTime) return aTime - bTime;

        var aMinutes = a.timeMinutes !== null ? a.timeMinutes : -1;
        var bMinutes = b.timeMinutes !== null ? b.timeMinutes : -1;
        return aMinutes - bMinutes;
    });

    return matches;
}

function isElliotName(value) {
    var normalized = normalizeText(value || "");
    return normalized.indexOf("feroux") !== -1 && normalized.indexOf("elliot") !== -1;
}

function normalizeText(value) {
    return value
        .toString()
        .toLowerCase()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9 ]/g, " ")
        .replace(/\s+/g, " ")
        .trim();
}

function cleanText(value) {
    return (value || "").toString().replace(/\s+/g, " ").trim();
}

function parseFrenchDate(value) {
    if (!value) return null;

    var parts = value.split("/");
    if (parts.length !== 3) return null;

    var day = Number(parts[0]);
    var month = Number(parts[1]);
    var year = Number(parts[2]);

    if (!day || !month || !year) return null;

    var dateObj = new Date(year, month - 1, day);
    if (Number.isNaN(dateObj.getTime())) return null;

    return dateObj;
}

function parseTimeToMinutes(value) {
    if (!value) return null;

    var match = value.toString().trim().match(/^(\d{1,2}):(\d{2})$/);
    if (!match) return null;

    var hour = Number(match[1]);
    var minute = Number(match[2]);
    if (hour > 23 || minute > 59) return null;

    return hour * 60 + minute;
}

function parseNumber(value) {
    if (value === null || value === undefined) return null;

    var clean = value
        .toString()
        .trim()
        .replace(/\s/g, "")
        .replace(",", ".")
        .replace("€", "");

    if (!clean) return null;

    var number = Number(clean);
    return Number.isFinite(number) ? number : null;
}

function computeSeason(dateObj) {
    if (!dateObj) return "Inconnue";

    var year = dateObj.getFullYear();
    var month = dateObj.getMonth() + 1;
    var startYear = month >= 8 ? year : year - 1;
    return startYear + "-" + (startYear + 1);
}

function populateFilters(matches) {
    var seasonFilter = document.getElementById("season-filter");
    var competitionFilter = document.getElementById("competition-filter");

    if (!seasonFilter || !competitionFilter) return;

    var seasons = uniqueValues(matches.map(function (m) { return m.season; }))
        .sort(function (a, b) {
            var aYear = Number(a.split("-")[0]) || 0;
            var bYear = Number(b.split("-")[0]) || 0;
            return bYear - aYear;
        });

    var competitions = uniqueValues(matches.map(function (m) { return m.competition; }))
        .sort(function (a, b) { return a.localeCompare(b, "fr"); });

    seasons.forEach(function (season) {
        seasonFilter.appendChild(createOption(season, season));
    });

    competitions.forEach(function (competition) {
        competitionFilter.appendChild(createOption(competition, competition));
    });
}

function createOption(value, text) {
    var option = document.createElement("option");
    option.value = value;
    option.textContent = text;
    return option;
}

function uniqueValues(values) {
    return Array.from(new Set(values.filter(Boolean)));
}

function applyFilters() {
    var seasonFilter = document.getElementById("season-filter");
    var competitionFilter = document.getElementById("competition-filter");

    if (!seasonFilter || !competitionFilter) return;

    var selectedSeason = seasonFilter.value;
    var selectedCompetition = competitionFilter.value;

    DASHBOARD_STATE.filteredMatches = DASHBOARD_STATE.allMatches.filter(function (match) {
        var seasonOk = selectedSeason === "all" || match.season === selectedSeason;
        var competitionOk = selectedCompetition === "all" || match.competition === selectedCompetition;
        return seasonOk && competitionOk;
    });

    updateKPIs(DASHBOARD_STATE.filteredMatches);
    updateCharts(DASHBOARD_STATE.filteredMatches);
    updateInsights(DASHBOARD_STATE.filteredMatches);
    renderMatchesTable(DASHBOARD_STATE.filteredMatches);
    updateMatchCount(DASHBOARD_STATE.filteredMatches.length);
}

function updateDataRange(matches) {
    var range = document.getElementById("data-range");
    if (!range || matches.length === 0) return;

    var validDates = matches
        .map(function (m) { return m.dateObj; })
        .filter(function (d) { return d !== null; })
        .sort(function (a, b) { return a - b; });

    if (validDates.length === 0) return;

    range.textContent = "Période analysée: " + formatDate(validDates[0]) + " → " + formatDate(validDates[validDates.length - 1]);
}

function updateMatchCount(count) {
    var node = document.getElementById("match-count");
    if (!node) return;

    node.textContent = count + " match" + (count > 1 ? "s" : "") + " affiché" + (count > 1 ? "s" : "");
}

function updateKPIs(matches) {
    var totalMatches = matches.length;
    var withIndemnity = matches.filter(function (m) { return m.indemnityKnown; });
    var totalIndemnity = withIndemnity.reduce(function (sum, m) {
        return sum + (m.indemnity || 0);
    }, 0);

    var avgIndemnity = withIndemnity.length ? totalIndemnity / withIndemnity.length : 0;
    var competitionCount = uniqueValues(matches.map(function (m) { return m.competition; })).length;
    var coverage = totalMatches ? (withIndemnity.length / totalMatches) * 100 : 0;

    var latest = getLatestMatch(matches);

    setText("kpi-total-matches", totalMatches.toString());
    setText("kpi-total-indemnity", formatEuro(totalIndemnity));
    setText("kpi-avg-indemnity", formatEuro(avgIndemnity));
    setText("kpi-competitions", competitionCount.toString());
    setText("kpi-last-match", latest ? formatDate(latest.dateObj) : "-");
    setText("kpi-indemnity-coverage", Math.round(coverage) + "%");
}

function getLatestMatch(matches) {
    return matches
        .filter(function (m) { return m.dateObj !== null; })
        .sort(function (a, b) { return b.dateObj - a.dateObj; })[0] || null;
}

function setText(id, value) {
    var node = document.getElementById(id);
    if (node) node.textContent = value;
}

function updateCharts(matches) {
    if (typeof Chart === "undefined") {
        if (!CHART_WARNING_SHOWN) {
            CHART_WARNING_SHOWN = true;
            setStatus("Données chargées, mais Chart.js est indisponible. Les KPI et le tableau restent utilisables.", true);
        }
        return;
    }

    renderMonthlyChart(matches);
    renderCompetitionChart(matches);
    renderWeekdayChart(matches);
    renderHostClubsChart(matches);
}

function renderMonthlyChart(matches) {
    var canvas = document.getElementById("chart-monthly");
    if (!canvas) return;

    var monthMap = new Map();

    matches.forEach(function (m) {
        if (!m.dateObj) return;
        var key = m.dateObj.getFullYear() + "-" + String(m.dateObj.getMonth() + 1).padStart(2, "0");

        if (!monthMap.has(key)) {
            monthMap.set(key, { count: 0, indemnity: 0 });
        }

        var entry = monthMap.get(key);
        entry.count += 1;
        entry.indemnity += m.indemnity || 0;
    });

    var keys = Array.from(monthMap.keys()).sort();
    var labels = keys.map(function (key) {
        var parts = key.split("-");
        var year = Number(parts[0]);
        var month = Number(parts[1]);
        return new Intl.DateTimeFormat("fr-FR", { month: "short", year: "2-digit" })
            .format(new Date(year, month - 1, 1));
    });

    var counts = keys.map(function (k) { return monthMap.get(k).count; });
    var indemnities = keys.map(function (k) { return round2(monthMap.get(k).indemnity); });

    destroyChart("monthly");

    DASHBOARD_STATE.charts.monthly = new Chart(canvas, {
        type: "bar",
        data: {
            labels: labels,
            datasets: [
                {
                    label: "Matchs",
                    data: counts,
                    backgroundColor: "rgba(250, 235, 215, 0.45)",
                    borderColor: "rgba(250, 235, 215, 0.8)",
                    borderWidth: 1,
                    yAxisID: "yMatches"
                },
                {
                    label: "Indemnités (€)",
                    data: indemnities,
                    type: "line",
                    borderColor: "#f6d596",
                    backgroundColor: "rgba(246, 213, 150, 0.2)",
                    pointRadius: 3,
                    pointHoverRadius: 4,
                    tension: 0.3,
                    yAxisID: "yEuro"
                }
            ]
        },
        options: getSharedChartOptions({
            scales: {
                x: getAxisStyle(),
                yMatches: getAxisStyle({
                    beginAtZero: true,
                    title: { display: true, text: "Matchs" }
                }),
                yEuro: getAxisStyle({
                    beginAtZero: true,
                    position: "right",
                    grid: { drawOnChartArea: false },
                    title: { display: true, text: "€" }
                })
            }
        })
    });
}

function renderCompetitionChart(matches) {
    var canvas = document.getElementById("chart-competition");
    if (!canvas) return;

    var counts = groupByCount(matches, "competition");
    var sorted = Object.entries(counts).sort(function (a, b) { return b[1] - a[1]; });

    var top = sorted.slice(0, 8);
    var others = sorted.slice(8).reduce(function (sum, entry) { return sum + entry[1]; }, 0);

    if (others > 0) {
        top.push(["Autres", others]);
    }

    var labels = top.map(function (entry) { return entry[0]; });
    var data = top.map(function (entry) { return entry[1]; });

    destroyChart("competition");

    DASHBOARD_STATE.charts.competition = new Chart(canvas, {
        type: "doughnut",
        data: {
            labels: labels,
            datasets: [{
                data: data,
                backgroundColor: [
                    "#f6d596",
                    "#d8bc8c",
                    "#bca57d",
                    "#8b9b9a",
                    "#6f8686",
                    "#557070",
                    "#395757",
                    "#243e3e",
                    "#1a2f2f"
                ],
                borderColor: "rgba(11, 22, 22, 0.95)",
                borderWidth: 2
            }]
        },
        options: getSharedChartOptions({
            plugins: {
                legend: {
                    display: true,
                    position: "bottom",
                    labels: { color: "rgba(250, 235, 215, 0.9)" }
                },
                tooltip: {
                    callbacks: {
                        label: function (context) {
                            var value = context.raw || 0;
                            var total = context.dataset.data.reduce(function (sum, current) { return sum + current; }, 0);
                            var percentage = total ? Math.round((value / total) * 100) : 0;
                            return context.label + ": " + value + " matchs (" + percentage + "%)";
                        }
                    }
                }
            }
        })
    });
}

function renderWeekdayChart(matches) {
    var canvas = document.getElementById("chart-weekday");
    if (!canvas) return;

    var labels = ["Lun", "Mar", "Mer", "Jeu", "Ven", "Sam", "Dim"];
    var counts = [0, 0, 0, 0, 0, 0, 0];
    var indemnity = [0, 0, 0, 0, 0, 0, 0];

    matches.forEach(function (m) {
        if (!m.dateObj) return;
        var jsDay = m.dateObj.getDay();
        var mondayBased = (jsDay + 6) % 7;
        counts[mondayBased] += 1;
        indemnity[mondayBased] += m.indemnity || 0;
    });

    destroyChart("weekday");

    DASHBOARD_STATE.charts.weekday = new Chart(canvas, {
        type: "bar",
        data: {
            labels: labels,
            datasets: [
                {
                    label: "Matchs",
                    data: counts,
                    backgroundColor: "rgba(250, 235, 215, 0.5)",
                    borderColor: "rgba(250, 235, 215, 0.85)",
                    borderWidth: 1,
                    yAxisID: "yMatches"
                },
                {
                    label: "Indemnités (€)",
                    data: indemnity.map(round2),
                    type: "line",
                    borderColor: "#f7cf8a",
                    tension: 0.25,
                    yAxisID: "yEuro"
                }
            ]
        },
        options: getSharedChartOptions({
            scales: {
                x: getAxisStyle(),
                yMatches: getAxisStyle({
                    beginAtZero: true,
                    title: { display: true, text: "Matchs" }
                }),
                yEuro: getAxisStyle({
                    beginAtZero: true,
                    position: "right",
                    grid: { drawOnChartArea: false },
                    title: { display: true, text: "€" }
                })
            }
        })
    });
}

function renderHostClubsChart(matches) {
    var canvas = document.getElementById("chart-host-clubs");
    if (!canvas) return;

    var map = new Map();

    matches.forEach(function (m) {
        var key = m.recevant || "Non renseigné";
        if (!map.has(key)) {
            map.set(key, { matches: 0, indemnity: 0 });
        }

        var entry = map.get(key);
        entry.matches += 1;
        entry.indemnity += m.indemnity || 0;
    });

    var sorted = Array.from(map.entries())
        .sort(function (a, b) { return b[1].matches - a[1].matches; })
        .slice(0, 10);

    var labels = sorted.map(function (entry) { return entry[0]; });
    var matchCounts = sorted.map(function (entry) { return entry[1].matches; });
    var indemnities = sorted.map(function (entry) { return round2(entry[1].indemnity); });

    destroyChart("hostClubs");

    DASHBOARD_STATE.charts.hostClubs = new Chart(canvas, {
        type: "bar",
        data: {
            labels: labels,
            datasets: [{
                label: "Matchs",
                data: matchCounts,
                backgroundColor: "rgba(246, 213, 150, 0.55)",
                borderColor: "rgba(246, 213, 150, 0.95)",
                borderWidth: 1,
                indemnity: indemnities
            }]
        },
        options: getSharedChartOptions({
            indexAxis: "y",
            scales: {
                x: getAxisStyle({
                    beginAtZero: true,
                    title: { display: true, text: "Matchs" }
                }),
                y: getAxisStyle()
            },
            plugins: {
                tooltip: {
                    callbacks: {
                        label: function (context) {
                            var matchesCount = context.raw || 0;
                            var euros = context.dataset.indemnity[context.dataIndex] || 0;
                            return matchesCount + " matchs • " + formatEuro(euros);
                        }
                    }
                }
            }
        })
    });
}

function destroyChart(key) {
    if (DASHBOARD_STATE.charts[key]) {
        DASHBOARD_STATE.charts[key].destroy();
        DASHBOARD_STATE.charts[key] = null;
    }
}

function getSharedChartOptions(overrides) {
    var base = {
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                labels: {
                    color: "rgba(250, 235, 215, 0.9)"
                }
            },
            tooltip: {
                backgroundColor: "rgba(7, 16, 16, 0.95)",
                titleColor: "#fff2dc",
                bodyColor: "#fff2dc",
                borderColor: "rgba(250, 235, 215, 0.28)",
                borderWidth: 1
            }
        }
    };

    return mergeOptions(base, overrides || {});
}

function getAxisStyle(overrides) {
    var base = {
        ticks: {
            color: "rgba(250, 235, 215, 0.82)",
            font: { size: 11 }
        },
        grid: {
            color: "rgba(250, 235, 215, 0.12)"
        },
        border: {
            color: "rgba(250, 235, 215, 0.2)"
        },
        title: {
            color: "rgba(250, 235, 215, 0.85)",
            font: { size: 11 }
        }
    };

    return mergeOptions(base, overrides || {});
}

function mergeOptions(target, source) {
    Object.keys(source).forEach(function (key) {
        if (source[key] && typeof source[key] === "object" && !Array.isArray(source[key])) {
            if (!target[key] || typeof target[key] !== "object") {
                target[key] = {};
            }
            mergeOptions(target[key], source[key]);
        } else {
            target[key] = source[key];
        }
    });

    return target;
}

function groupByCount(items, key) {
    return items.reduce(function (acc, item) {
        var value = item[key] || "Non renseigné";
        acc[value] = (acc[value] || 0) + 1;
        return acc;
    }, {});
}

function updateInsights(matches) {
    var list = document.getElementById("insight-list");
    if (!list) return;

    if (matches.length === 0) {
        list.innerHTML = "<li>Aucun match pour les filtres sélectionnés.</li>";
        return;
    }

    var competitions = Object.entries(groupByCount(matches, "competition"))
        .sort(function (a, b) { return b[1] - a[1]; });

    var topCompetition = competitions[0];

    var byMonth = new Map();
    matches.forEach(function (m) {
        if (!m.dateObj) return;
        var monthKey = m.dateObj.getFullYear() + "-" + String(m.dateObj.getMonth() + 1).padStart(2, "0");
        byMonth.set(monthKey, (byMonth.get(monthKey) || 0) + 1);
    });

    var topMonthEntry = Array.from(byMonth.entries()).sort(function (a, b) { return b[1] - a[1]; })[0];
    var topMonthLabel = "-";
    if (topMonthEntry) {
        var monthParts = topMonthEntry[0].split("-");
        topMonthLabel = new Intl.DateTimeFormat("fr-FR", { month: "long", year: "numeric" })
            .format(new Date(Number(monthParts[0]), Number(monthParts[1]) - 1, 1));
    }

    var byDay = [0, 0, 0, 0, 0, 0, 0];
    var dayLabels = ["lundi", "mardi", "mercredi", "jeudi", "vendredi", "samedi", "dimanche"];
    matches.forEach(function (m) {
        if (!m.dateObj) return;
        byDay[(m.dateObj.getDay() + 6) % 7] += 1;
    });

    var peakDayIndex = 0;
    byDay.forEach(function (value, index) {
        if (value > byDay[peakDayIndex]) peakDayIndex = index;
    });

    var withIndemnity = matches.filter(function (m) { return m.indemnityKnown; });
    var totalIndemnity = withIndemnity.reduce(function (sum, m) { return sum + (m.indemnity || 0); }, 0);

    list.innerHTML = "";

    addInsight(list, "Compétition principale: " + topCompetition[0] + " (" + topCompetition[1] + " matchs).");
    addInsight(list, "Période la plus dense: " + topMonthLabel + " (" + (topMonthEntry ? topMonthEntry[1] : 0) + " matchs).");
    addInsight(list, "Jour le plus fréquent: " + dayLabels[peakDayIndex] + " (" + byDay[peakDayIndex] + " matchs).");
    addInsight(list, "Indemnités Elliot sur ce périmètre: " + formatEuro(totalIndemnity) + ".");
}

function addInsight(listNode, text) {
    var item = document.createElement("li");
    item.textContent = text;
    listNode.appendChild(item);
}

function renderMatchesTable(matches) {
    var body = document.getElementById("matches-table-body");
    if (!body) return;

    body.innerHTML = "";

    var sorted = matches.slice().sort(function (a, b) {
        var bTime = b.dateObj ? b.dateObj.getTime() : -Infinity;
        var aTime = a.dateObj ? a.dateObj.getTime() : -Infinity;

        if (bTime !== aTime) return bTime - aTime;

        var bMinutes = b.timeMinutes !== null ? b.timeMinutes : -1;
        var aMinutes = a.timeMinutes !== null ? a.timeMinutes : -1;
        return bMinutes - aMinutes;
    });

    sorted.slice(0, 70).forEach(function (match) {
        var row = document.createElement("tr");

        row.innerHTML = ""
            + "<td>" + escapeHtml(formatDate(match.dateObj)) + "</td>"
            + "<td>" + escapeHtml(match.heure || "-") + "</td>"
            + "<td>" + escapeHtml(match.competition) + "</td>"
            + "<td>" + escapeHtml(match.visiteur) + "</td>"
            + "<td>" + escapeHtml(match.recevant) + "</td>"
            + "<td><span class=\"role-badge\">Arbitre " + match.role + "</span></td>"
            + "<td class=\"indemnity-cell\">" + (match.indemnityKnown ? escapeHtml(formatEuro(match.indemnity)) : "-") + "</td>";

        body.appendChild(row);
    });
}

function formatDate(dateObj) {
    if (!dateObj) return "-";

    return new Intl.DateTimeFormat("fr-FR", {
        day: "2-digit",
        month: "short",
        year: "numeric"
    }).format(dateObj);
}

function formatEuro(value) {
    return new Intl.NumberFormat("fr-FR", {
        style: "currency",
        currency: "EUR",
        minimumFractionDigits: 2,
        maximumFractionDigits: 2
    }).format(value || 0);
}

function round2(value) {
    return Math.round((value || 0) * 100) / 100;
}

function setStatus(message, isError) {
    var box = document.getElementById("status-box");
    if (!box) return;

    box.classList.remove("hidden", "error");
    if (isError) {
        box.classList.add("error");
    }

    box.textContent = message;

    if (!isError) {
        setTimeout(function () {
            box.classList.add("hidden");
        }, 2500);
    }
}

function escapeHtml(value) {
    return String(value)
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/\"/g, "&quot;")
        .replace(/'/g, "&#039;");
}
